#include <iostream>

template <typename T>
T findMax(T a, T b) {
    return (a > b) ? a : b;
}

int main() {
    int int1 = 10;
    int int2 = 5;
    std::cout << "Max of " << int1 << " and " << int2 << " is: " << findMax(int1, int2) << std::endl;

    int int3 = 5;
    int int4 = 10;
    std::cout << "Max of " << int3 << " and " << int4 << " is: " << findMax(int3, int4) << std::endl;

    int int5 = 7;
    int int6 = 7;
    std::cout << "Max of " << int5 << " and " << int6 << " is: " << findMax(int5, int6) << std::endl;

    double double1 = 3.14;
    double double2 = 2.71;
    std::cout << "Max of " << double1 << " and " << double2 << " is: " << findMax(double1, double2) << std::endl;

    double double3 = 2.71;
    double double4 = 3.14;
    std::cout << "Max of " << double3 << " and " << double4 << " is: " << findMax(double3, double4) << std::endl;

    return 0;
}
